		<-bm.ctx.Done()

		// ķĆĆÕć║µŚČķ£ĆĶ”üÕłĀķÖż
		bm.mux.Lock()
		delete(bm.active, betype)
		bm.mux.Unlock()

		bm.wg.Done()
	}()

	return be, nil
}

func Register(name string, ctor BackendCtor) {
