						// Õ”éµ×£ÕÅæńö¤Õż▒Ķ┤ź, ÕłÖÕ░ØĶ»ĢÕø×µöČ fdb ķģŹńĮ«.
						if err := nw.dev.DelFDB(neighbor{IP: event.Lease.Attrs.PublicIP, MAC: net.HardwareAddr(vxlanAttrs.VtepMAC)}); err != nil {
