	for idx := range r.cidrSets {
		// õ╗ÄÕ»╣Õ║öńÜä cidr ķøåÕÉłķćīÕłåķģŹ
		podCIDR, err := r.cidrSets[idx].AllocateNext()
		if err != nil {
			// Õ”éµ×£µ£ēÕ╝éÕĖĖÕłÖÕ£© nodesInProcessing ķøåÕÉłõĖŁÕłĀķÖż
			r.removeNodeFromProcessing(node.Name)
			return fmt.Errorf("failed to allocate cidr from cluster cidr at idx:%v: %v", idx, err)
		}
		allocated.allocatedCIDRs[idx] = podCIDR
	}

	// õĖŖķØóńÜäķĆ╗ĶŠæÕÅ¬µś»õĖ║ node ńö│Ķ»ĘÕłåķģŹ cidr Õ£░ÕØĆµ«Ą
	// ĶĆīÕģĘõĮōµø┤µ¢░ node Õ»╣Ķ▒Īõ┐Īµü»ÕłÖµś»Õ╝éµŁźńö▒ worker ÕŹÅń©ŗÕżäńÉå.
	r.nodeCIDRUpdateChannel <- allocated
	return nil
}
