func (s *CidrSet) AllocateNext() (*net.IPNet, error) {
	s.Lock()
	defer s.Unlock()

	// Õ”éµ×£ÕĮōÕēŹÕłåķģŹńÜä cidr ÕĘ▓ń╗ÅńŁēõ║Ä maxCIDRs, ÕłÖńø┤µÄźµŚĀÕē®õĮÖ cidr Õ£░ÕØĆµ«ĄķöÖĶ»».
	if s.allocatedCIDRs == s.maxCIDRs {
		return nil, ErrCIDRRangeNoCIDRsRemaining
	}

	candidate := s.nextCandidate
	var i int
	// õ╗ÄõĖŖµ¼ĪńÜä candidate Õ╝ĆÕ¦ŗÕŠ¬ńÄ»ķüŹÕÄå, ńø┤Õł░µēŠÕł░ÕÅ»ńö©ńÜä cidr.
	for i = 0; i < s.maxCIDRs; i++ {
		// Õ”éµ×£ÕĮōÕēŹõĮŹĶ┐śµ£¬õĮ┐ńö©, ÕłÖõĮ┐ńö©Ķ»ź candidate.
		if s.used.Bit(candidate) == 0 {
			break
		}

		// ĶĘ¤ maxCIDRs ÕÅ¢µæĖĶ«Īń«ŚÕć║ candidate
		candidate = (candidate + 1) % s.maxCIDRs
	}

	// õĖŗµ¼ĪńÜä candidate õĮŹńĮ«
	s.nextCandidate = (candidate + 1) % s.maxCIDRs

	// ķģŹńĮ« used bitmap õĖŁ candidate õĮŹńĮ« bit õĖ║ 1
	s.used.SetBit(&s.used, candidate, 1)

	// µ»Åµ¼ĪÕłåķģŹµłÉÕŖ¤ķāĮõ╝ÜÕŖĀõĖĆ
	s.allocatedCIDRs++

	return s.indexToCIDRBlock(candidate), nil
}
